using ChurnPredictor;
using Microsoft.Extensions.ML;

var builder = WebApplication.CreateBuilder(args);

var dataPath = Path.Combine(builder.Environment.ContentRootPath, "Data", "customers.csv");
var modelPath = Path.Combine(builder.Environment.ContentRootPath, "Data", "ChurnModel.zip");

// Train on startup and register the pooled prediction engine (thread-safe)
var report = ModelTrainer.Train(dataPath, modelPath);
Console.WriteLine(report);

builder.Services.AddPredictionEnginePool<CustomerData, ChurnPrediction>()
    .FromFile(modelPath);

var app = builder.Build();

app.MapGet("/", () => "Churn Predictor API — POST to /predict");

app.MapPost("/predict", (CustomerInput input, PredictionEnginePool<CustomerData, ChurnPrediction> pool) =>
{
    var data = new CustomerData
    {
        Age = input.Age,
        Income = input.Income,
        Region = input.Region,
        PurchaseHistory = input.PurchaseHistory
    };
    var result = pool.Predict(data);
    return Results.Ok(new
    {
        Churned = result.Churned,
        Probability = result.Probability
    });
});

app.Run();

public record CustomerInput(float Age, float Income, string Region, float PurchaseHistory);

