using Microsoft.ML;

namespace ChurnPredictor;

public static class ModelTrainer
{
    public static string Train(string dataPath, string modelPath)
    {
        var mlContext = new MLContext(seed: 42);

        var rawData = mlContext.Data.LoadFromTextFile<CustomerData>(
            dataPath, hasHeader: true, separatorChar: ',');

        // Map "Yes"/"No" → boolean Label, encode Region, build features
        var pipeline = mlContext.Transforms.CustomMapping<CustomerData, LabelMapping>(
                (input, output) => output.Label = string.Equals(input.Churned, "Yes", StringComparison.OrdinalIgnoreCase),
                contractName: null)
            .Append(mlContext.Transforms.Categorical.OneHotEncoding("RegionEncoded", "Region"))
            .Append(mlContext.Transforms.Concatenate("Features", "Age", "Income", "RegionEncoded", "PurchaseHistory"))
            .Append(mlContext.Transforms.NormalizeMinMax("Features"))
            .Append(mlContext.BinaryClassification.Trainers.SdcaLogisticRegression(
                labelColumnName: "Label",
                featureColumnName: "Features"));

        var rowCount = (int)rawData.GetColumn<float>("Age").LongCount();
        string report;

        if (rowCount >= 20)
        {
            var split = mlContext.Data.TrainTestSplit(rawData, testFraction: 0.2, seed: 42);
            var model = pipeline.Fit(split.TrainSet);
            var predictions = model.Transform(split.TestSet);
            var metrics = mlContext.BinaryClassification.Evaluate(predictions, labelColumnName: "Label");

            report = $"""
                === Model Evaluation ===
                Accuracy:  {metrics.Accuracy:F4}
                AUC:       {metrics.AreaUnderRocCurve:F4}
                F1 Score:  {metrics.F1Score:F4}
                Positive Precision: {metrics.PositivePrecision:F4}
                Positive Recall:    {metrics.PositiveRecall:F4}
                """;

            mlContext.Model.Save(model, rawData.Schema, modelPath);
        }
        else
        {
            // Too few rows for a meaningful train/test split — train on all data
            var model = pipeline.Fit(rawData);
            report = $"""
                === Model Trained ===
                Rows: {rowCount} (too few for train/test split; evaluation skipped)
                Add more data for reliable metrics.
                """;
            mlContext.Model.Save(model, rawData.Schema, modelPath);
        }

        return report;
    }
}

